// ============================================================
// SYMPTOM TRIAGE TOOL
// ============================================================
const EMERGENCY_KEYWORDS = [
  'chest pain','chest tightness','heart attack','cardiac arrest',
  'difficulty breathing','can\'t breathe','shortness of breath',
  'stroke','face drooping','arm weakness','speech difficulty',
  'suicidal','want to die','kill myself','end my life','self harm',
  'severe bleeding','uncontrolled bleeding','coughing blood','vomiting blood',
  'seizure','unconscious','passed out','anaphylaxis','allergic reaction',
  'severe allergic','overdose','poisoning','choking','drowning'
];

const URGENT_KEYWORDS = [
  'high fever','fever above 39','fever above 103','severe headache',
  'sudden vision','eye pain','ear pain','urinary pain',
  'abdominal pain','vomiting','diarrhea','rash','swelling',
  'back pain','joint pain','dizziness','fainting'
];

const symptomText = (symptoms || '').toLowerCase();

// Check for EMERGENCY
const isEmergency = EMERGENCY_KEYWORDS.some(k => symptomText.includes(k)) || severity === 'severe';
if (isEmergency) {
  return JSON.stringify({
    urgency: 'EMERGENCY',
    action: 'Call 911 or go to the nearest Emergency Room immediately.',
    crisis: true,
    message: '🚨 EMERGENCY DETECTED. This patient requires IMMEDIATE emergency care.',
    care_setting: 'Emergency Room (ER)',
    disclaimer: 'This is an AI-generated triage assessment and is NOT a substitute for professional medical advice.'
  });
}

// Check for URGENT
const isUrgent = URGENT_KEYWORDS.some(k => symptomText.includes(k)) || severity === 'moderate';
if (isUrgent) {
  return JSON.stringify({
    urgency: 'URGENT',
    action: 'Visit an urgent care center or contact your doctor within the next few hours.',
    crisis: false,
    message: 'These symptoms require prompt medical attention today.',
    care_setting: 'Urgent Care or Primary Care (same day)',
    disclaimer: 'This is an AI-generated triage assessment and is NOT a substitute for professional medical advice.'
  });
}

// ROUTINE
return JSON.stringify({
  urgency: 'ROUTINE',
  action: 'Schedule an appointment with your primary care physician.',
  crisis: false,
  message: 'These symptoms can be addressed with a routine appointment.',
  care_setting: 'Primary Care or Telehealth',
  disclaimer: 'This is an AI-generated triage assessment and is NOT a substitute for professional medical advice.'
});

