// ============================================================
// APPOINTMENT MANAGEMENT TOOL — calls your Custom EHR REST API
// ============================================================
const baseUrl = $vars.EHR_API_BASE_URL || 'http://localhost:8080/api';
const apiKey  = $vars.EHR_API_KEY || 'dev-key';

const headers = {
  'Content-Type': 'application/json',
  'x-api-key': apiKey
};

try {
  if (action === 'get_slots') {
    const res = await fetch(`${baseUrl}/appointments/slots?department=${encodeURIComponent(department||'General')}&date=${preferred_date||''}`, { headers });
    const data = await res.json();
    if (!data.slots || data.slots.length === 0) return 'No available slots found for the requested date and department. Please try a different date.';
    const slotList = data.slots.map(s => `• ${s.time} — Dr. ${s.doctor} (${s.department})`).join('\n');
    return `Available appointment slots:\n${slotList}`;
  }

  if (action === 'book') {
    const res = await fetch(`${baseUrl}/appointments/book`, {
      method: 'POST', headers,
      body: JSON.stringify({ patient_id, department, preferred_date, reason })
    });
    const data = await res.json();
    return `✅ Appointment booked!\n📅 Date: ${data.date}\n🕐 Time: ${data.time}\n👨‍⚕️ Doctor: Dr. ${data.doctor}\n🏥 Department: ${data.department}\n🔖 Confirmation: ${data.confirmation_id}\n\nYou will receive a reminder 24 hours before your appointment.`;
  }

  if (action === 'reschedule') {
    const res = await fetch(`${baseUrl}/appointments/${appointment_id}/reschedule`, {
      method: 'PUT', headers,
      body: JSON.stringify({ preferred_date })
    });
    const data = await res.json();
    return `✅ Appointment rescheduled!\n📅 New date: ${data.date}\n🕐 New time: ${data.time}\n🔖 Updated confirmation: ${data.confirmation_id}`;
  }

  if (action === 'cancel') {
    const res = await fetch(`${baseUrl}/appointments/${appointment_id}/cancel`, {
      method: 'DELETE', headers
    });
    const data = await res.json();
    return `✅ Appointment ${appointment_id} has been cancelled. ${data.message || ''}`;
  }

  return 'Unknown action. Please specify: book, reschedule, cancel, or get_slots.';

} catch (err) {
  return `Appointment service temporarily unavailable. Please call our front desk or try again shortly. Error: ${err.message}`;
}

