// ============================================================
// EHR LOOKUP TOOL — Generic REST API
// ============================================================
const baseUrl = $vars.EHR_API_BASE_URL || 'http://localhost:8080/api';
const apiKey  = $vars.EHR_API_KEY || 'dev-key';

try {
  const res = await fetch(`${baseUrl}/patients/${patient_id}/records/${record_type}`, {
    headers: { 'x-api-key': apiKey, 'Content-Type': 'application/json' }
  });

  if (res.status === 401) return 'Authentication required. Please verify your identity before accessing medical records.';
  if (res.status === 404) return 'No records found for this patient. Please contact the front desk if you believe this is an error.';
  if (!res.ok) return `Unable to retrieve ${record_type} at this time. Please try again or contact support.`;

  const data = await res.json();

  // Format based on type
  if (record_type === 'lab_results' && data.results) {
    const labs = data.results.map(r =>
      `• ${r.test_name}: ${r.value} ${r.unit} (${r.status === 'normal' ? '✅ Normal' : '⚠️ Abnormal'}) — ${r.date}`
    ).join('\n');
    return `Recent lab results for your records:\n${labs}\n\nPlease discuss any abnormal results with your doctor.`;
  }

  if (record_type === 'medications' && data.medications) {
    const meds = data.medications.map(m =>
      `• ${m.name} ${m.dosage} — ${m.frequency} (prescribed by Dr. ${m.prescriber})`
    ).join('\n');
    return `Your current medications:\n${meds}\n\nFor refill requests, please let me know.`;
  }

  if (record_type === 'summary') {
    return `Patient Summary:\n• Name: ${data.name}\n• DOB: ${data.dob}\n• Blood type: ${data.blood_type}\n• Allergies: ${data.allergies?.join(', ') || 'None recorded'}\n• Conditions: ${data.conditions?.join(', ') || 'None recorded'}\n• Last visit: ${data.last_visit}`;
  }

  return JSON.stringify(data, null, 2);

} catch (err) {
  return `Unable to access medical records. Please try again or contact the hospital directly. Error: ${err.message}`;
}

