const accountSid = $vars.TWILIO_ACCOUNT_SID;
const authToken  = $vars.TWILIO_AUTH_TOKEN;
const fromNumber = $vars.TWILIO_WHATSAPP_FROM || 'whatsapp:+14155238886';

const credentials = btoa(`${accountSid}:${authToken}`);
const body = new URLSearchParams({
  From: fromNumber,
  To: `whatsapp:${to}`,
  Body: `🏥 City General Hospital\n\n${message}\n\n⚠️ This message is from an AI assistant. For emergencies, call 911.`
});

try {
  const res = await fetch(`https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`, {
    method: 'POST',
    headers: { 'Authorization': `Basic ${credentials}`, 'Content-Type': 'application/x-www-form-urlencoded' },
    body: body.toString()
  });
  const data = await res.json();
  if (data.sid) return `✅ WhatsApp notification sent successfully. (SID: ${data.sid})`;
  return `Failed to send WhatsApp: ${JSON.stringify(data)}`;
} catch (err) {
  return `WhatsApp service error: ${err.message}`;
}

