const baseUrl  = $vars.EHR_API_BASE_URL || 'http://localhost:8080/api';
const apiKey   = $vars.EHR_API_KEY || 'dev-key';
const ticketId = 'TKT-' + Date.now();

try {
  await fetch(`${baseUrl}/handoff`, {
    method: 'POST',
    headers: { 'x-api-key': apiKey, 'Content-Type': 'application/json' },
    body: JSON.stringify({ ticket_id: ticketId, reason, priority, summary, department, timestamp: new Date().toISOString() })
  });
} catch(e) { /* continue even if API call fails */ }

if (priority === 'emergency') {
  return `🚨 EMERGENCY ESCALATION INITIATED\n\nTicket: ${ticketId}\n\nIf you are experiencing a life-threatening emergency:\n📞 CALL 911 IMMEDIATELY\n\nFor the hospital emergency line: Call (555) 000-0000\n\nA staff member has been notified and will contact you shortly.`;
}

return `✅ Handing you over to our team.\n\n📋 Ticket: ${ticketId}\n🏥 Department: ${department || 'Reception'}\n⏱️ Expected wait: ${priority === 'high' ? '2-5 minutes' : '5-10 minutes'}\n\nA staff member will join this conversation or call you shortly. You can also call us directly at (555) 000-0000.`;

